import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { FaCarSide } from 'react-icons/fa';

const Booking = () => {
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(false);
    const [bookingDetails, setBookingDetails] = useState({
        pickup: '',
        destination: '',
        cabType: 'Mini',
        fare: 25
    });

    // --- INTERNAL STYLES (White screen fix) ---
    const styles = {
        container: { display: 'flex', height: '100vh', backgroundColor: '#f8f9fc', fontFamily: 'sans-serif' },
        sidebar: { width: '280px', backgroundColor: '#ffffff', borderRight: '1px solid #edf2f7', padding: '40px 24px', display: 'flex', flexDirection: 'column' },
        logoBox: { display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '40px' },
        logoIcon: { fontSize: '32px', color: '#0052cc' },
        logoText: { fontSize: '28px', fontWeight: 'bold', color: '#1e293b', margin: 0 },
        navItem: { padding: '14px 16px', cursor: 'pointer', fontSize: '16px', color: '#64748b', borderRadius: '8px', marginBottom: '8px' },
        activeNav: { padding: '14px 16px', cursor: 'pointer', fontSize: '16px', backgroundColor: '#f0f7ff', color: '#0052cc', fontWeight: '600', borderRadius: '8px', marginBottom: '8px' },
        main: { flex: 1, padding: '40px', overflowY: 'auto' },
        header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '35px' },
        grid: { display: 'flex', gap: '30px', height: '600px' },
        form: { flex: '0 0 380px', backgroundColor: '#ffffff', padding: '35px', borderRadius: '24px', boxShadow: '0 10px 20px rgba(0,0,0,0.05)' },
        input: { width: '100%', padding: '14px', borderRadius: '12px', border: '1.5px solid #e2e8f0', marginTop: '8px', outline: 'none' },
        btn: { width: '100%', padding: '18px', backgroundColor: '#10b981', color: '#fff', border: 'none', borderRadius: '16px', cursor: 'pointer', fontWeight: '700', marginTop: '20px' },
        map: { flex: 1, borderRadius: '24px', overflow: 'hidden', border: '1px solid #e2e8f0' }
    };

    const handleConfirmBooking = async () => {
        if (!bookingDetails.pickup || !bookingDetails.destination) {
            alert("Please enter both pickup and destination.");
            return;
        }
        setIsLoading(true);
        try {
            // Backend URL update kar lena agar zarurat ho
            await axios.post('http://localhost:5000/api/rides/request', {
                pickupLocation: bookingDetails.pickup,
                dropLocation: bookingDetails.destination,
                fare: bookingDetails.fare,
                passengerId: "123" // Temporary ID
            });
            setTimeout(() => {
                setIsLoading(true);
                alert("Ride Confirmed!");
                setIsLoading(false);
            }, 2000);
        } catch (error) {
            setIsLoading(false);
            alert("Server connection failed!");
        }
    };

    return (
        <div style={styles.container}>
            <aside style={styles.sidebar}>
                <div style={styles.logoBox}>
                    <FaCarSide style={styles.logoIcon} />
                    <h1 style={styles.logoText}>Ucab</h1>
                </div>
                <nav style={{ flex: 1 }}>
                    <div onClick={() => navigate('/profile')} style={styles.navItem}>👤 Profile</div>
                    <div onClick={() => navigate('/booking')} style={styles.activeNav}>🚗 Book a Ride</div>
                    <div onClick={() => navigate('/payments')} style={styles.navItem}>💳 Payments</div>
                    <div onClick={() => navigate('/support')} style={styles.navItem}>⚙️ Support</div>
                </nav>
            </aside>

            <main style={styles.main}>
                <header style={styles.header}>
                    <h2 style={{fontWeight:'700'}}>Cab Booking</h2>
                    <div style={{backgroundColor:'#0052cc', color:'#fff', padding:'10px 15px', borderRadius:'50%'}}>HV</div>
                </header>

                <div style={styles.grid}>
                    <section style={styles.form}>
                        <h4 style={{fontSize:'12px', color:'#94a3b8', marginBottom:'20px'}}>BOOK YOUR RIDE</h4>
                        <label style={{fontSize:'13px', fontWeight:'600'}}>Pickup</label>
                        <input type="text" placeholder="Pickup..." style={styles.input} onChange={(e) => setBookingDetails({...bookingDetails, pickup: e.target.value})} />
                        
                        <div style={{marginTop:'20px'}}>
                            <label style={{fontSize:'13px', fontWeight:'600'}}>Destination</label>
                            <input type="text" placeholder="Where to?" style={styles.input} onChange={(e) => setBookingDetails({...bookingDetails, destination: e.target.value})} />
                        </div>

                        <button onClick={handleConfirmBooking} style={styles.btn}>
                            {isLoading ? "SEARCHING..." : "CONFIRM RIDE"}
                        </button>
                    </section>

                    <section style={styles.map}>
                        <iframe title="map" width="100%" height="100%" frameBorder="0" src="https://www.openstreetmap.org/export/embed.html?bbox=77.1,28.5,77.3,28.7&layer=mapnik" />
                    </section>
                </div>
            </main>
        </div>
    );
};

export default Booking;
